export default function Footer() {
  return (
    <>
      <style>{`
        .pgn-footer {
          position: relative;
          background: var(--ds-color-bg-surface);
          padding: 72px 40px 0;
          overflow: hidden;
        }

        /* top blue separator */
        .pgn-footer::before {
          content: '';
          position: absolute;
          top: 0; left: 0; right: 0;
          height: 1px;
          background: linear-gradient(to right,
            transparent 0%,
            rgba(22,106,253,0.45) 30%,
            rgba(22,106,253,0.6)  50%,
            rgba(22,106,253,0.45) 70%,
            transparent 100%
          );
        }
        /* soft glow behind separator */
        .pgn-footer::after {
          content: '';
          position: absolute;
          top: -40px; left: 50%;
          transform: translateX(-50%);
          width: 500px;
          height: 80px;
          background: radial-gradient(ellipse, rgba(22,106,253,0.14) 0%, transparent 70%);
          pointer-events: none;
        }

        .pgn-footer-inner {
          max-width: 1060px;
          margin: 0 auto;
          display: grid;
          grid-template-columns: 1.4fr 1fr 1fr;
          gap: 0 64px;
          padding-bottom: 56px;
        }

        /* brand col */
        .pgn-footer-brand {
          display: flex;
          flex-direction: column;
          gap: 16px;
        }
        .pgn-footer-logo {
          display: inline-flex;
          align-items: center;
          text-decoration: none;
          opacity: 0.92;
          transition: opacity 0.2s ease;
        }
        .pgn-footer-logo:hover { opacity: 1; }
        .pgn-footer-tagline {
          font-size: 13.5px;
          line-height: 1.65;
          color: rgba(202,215,250,0.48);
          max-width: 240px;
        }
        .pgn-footer-social {
          display: flex;
          gap: 10px;
          margin-top: 8px;
        }
        .pgn-footer-social-btn {
          width: 34px;
          height: 34px;
          border-radius: 9px;
          border: 1px solid rgba(183,214,255,0.12);
          background: rgba(6,24,41,0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          color: rgba(183,214,255,0.5);
          text-decoration: none;
          transition: color 0.2s ease, border-color 0.2s ease, background 0.2s ease;
        }
        .pgn-footer-social-btn:hover {
          color: #fff;
          border-color: rgba(22,106,253,0.4);
          background: rgba(22,106,253,0.1);
        }

        /* link cols */
        .pgn-footer-col {
          display: flex;
          flex-direction: column;
          gap: 12px;
        }
        .pgn-footer-col-label {
          font-size: 11px;
          font-weight: 600;
          letter-spacing: 0.18em;
          text-transform: uppercase;
          color: rgba(183,214,255,0.35);
          margin-bottom: 4px;
        }
        .pgn-footer-link {
          font-size: 13.5px;
          color: rgba(202,215,250,0.52);
          text-decoration: none;
          transition: color 0.2s ease;
        }
        .pgn-footer-link:hover { color: #fff; }

        /* bottom bar */
        .pgn-footer-bottom {
          max-width: 1060px;
          margin: 0 auto;
          border-top: 1px solid rgba(183,214,255,0.07);
          padding: 20px 0 28px;
          display: flex;
          align-items: center;
          justify-content: space-between;
          gap: 16px;
        }
        .pgn-footer-copy {
          font-size: 12px;
          color: rgba(202,215,250,0.3);
        }
        .pgn-footer-copy a {
          color: rgba(202,215,250,0.4);
          text-decoration: none;
          transition: color 0.2s;
        }
        .pgn-footer-copy a:hover { color: rgba(202,215,250,0.7); }
        .pgn-footer-badge {
          font-size: 11px;
          font-weight: 600;
          color: rgba(183,214,255,0.35);
          letter-spacing: 0.12em;
          text-transform: uppercase;
        }

        @media (max-width: 768px) {
          .pgn-footer { padding: 56px 24px 0; }
          .pgn-footer-inner {
            grid-template-columns: 1fr 1fr;
            gap: 40px 32px;
          }
          .pgn-footer-brand { grid-column: 1 / -1; }
        }
        @media (max-width: 480px) {
          .pgn-footer-inner { grid-template-columns: 1fr; }
          .pgn-footer-bottom { flex-direction: column; align-items: flex-start; gap: 8px; }
        }
      `}</style>

      <footer className="pgn-footer">
        <div className="pgn-footer-inner">

          {/* ── Brand ── */}
          <div className="pgn-footer-brand">
            <a href="#hero" className="pgn-footer-logo" aria-label="PigeonPag">
              <PigeonLogo />
            </a>
            <p className="pgn-footer-tagline">
              A infraestrutura Pix que o seu negócio merece — com alta aprovação, zero instabilidades e taxas justas.
            </p>
            <div className="pgn-footer-social">
              <a href="#" className="pgn-footer-social-btn" aria-label="Instagram">
                <IconInstagram />
              </a>
            </div>
          </div>

          {/* ── Link columns ── */}
          {LINKS.map(col => (
            <div key={col.label} className="pgn-footer-col">
              <span className="pgn-footer-col-label">{col.label}</span>
              {col.items.map(item => (
                <a key={item.name} href={item.href} className="pgn-footer-link">
                  {item.name}
                </a>
              ))}
            </div>
          ))}

        </div>

        {/* ── Bottom bar ── */}
        <div className="pgn-footer-bottom">
          <p className="pgn-footer-copy">
            © 2025 PigeonPag · Todos os direitos reservados ·{' '}
            <a href="#termos">Termos</a> · <a href="#privacidade">Privacidade</a>
          </p>
          <span className="pgn-footer-badge">Pix · Seguro · Confiável</span>
        </div>
      </footer>
    </>
  )
}
